body.script:
// 
(function(){
  var c=document.getElementById('bgCanvas'),ctx=c.getContext('2d');
  function res(){c.width=window.innerWidth;c.height=window.innerHeight}
  res();window.addEventListener('resize',res);
  var pts=[];
  for(var i=0;i<55;i++)pts.push({x:Math.random()*c.width,y:Math.random()*c.height,vx:(Math.random()-.5)*.5,vy:(Math.random()-.5)*.5,r:Math.random()*2+.5,o:Math.random()*.5+.1});
  function draw(){
    ctx.clearRect(0,0,c.width,c.height);
    pts.forEach(p=>{
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle='rgba(0,0,255,'+p.o+')';ctx.fill();
      p.x+=p.vx;p.y+=p.vy;
      if(p.x<0||p.x>c.width)p.vx*=-1;if(p.y<0||p.y>c.height)p.vy*=-1;
    });
    for(var a=0;a<pts.length;a++)for(var b=a+1;b<pts.length;b++){
      var dx=pts[a].x-pts[b].x,dy=pts[a].y-pts[b].y,d=Math.sqrt(dx*dx+dy*dy);
      if(d<140){ctx.beginPath();ctx.moveTo(pts[a].x,pts[a].y);ctx.lineTo(pts[b].x,pts[b].y);ctx.strokeStyle='rgba(0,0,255,'+(0.1*(1-d/140))+')';ctx.lineWidth=.6;ctx.stroke()}
    }
    requestAnimationFrame(draw);
  }
  draw();
})();

const FOLDERS=[
  {id:'games',name:'Games',color:'#3b82f6',projects:[
    {name:'SN GN Math 2026',desc:"Built off of GN Math with more content and better organization.",url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Story-Network-GN-Math-2026@latest/index.html'},
    {name:'SN Smash Bros',desc:'A Smash Bros inspired fighting game by Story Network.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Smash-Bros@latest/index.html'}
  ]},
  {id:'other',name:'Other',color:'#a855f7',projects:[
    {name:'SN Chat',desc:'A Chatting Website made by Camzzz.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Story-Network-Chat@b5daa59/index.html'},
    {name:'SN Casino',desc:'A FAKE gambling site for FUN, no REAL MONEY USED.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Casino@latest/index.html'}
  ]},
  {id:'proxy',name:'Proxy',color:'#22c55e',projects:[
    {name:'Zicon',desc:"Browser Engine unbl*cker for Chromebooks.",url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Zicon@latest/index.html'},
    {name:'VSCL',desc:'Proxy tool for Securly monitored Chromebooks.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/VSCL@latest/index.html'},
    {name:'Raz.Launcher',desc:'A proxy launcher — currently non-functional.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/raz.launcher@latest/index.html'}
  ]},
  {id:'utilities',name:'Utilities',color:'#4facfe',projects:[
    {name:'SN Code Runner',desc:'Run code snippets directly in your browser.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Code-Runner@latest/index.html'},
    {name:'SN Tools',desc:'Useful tools for developers.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Tools@latest/index.html'},
    {name:'CodeHS Launching',desc:'Launcher utility for CodeHS projects.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/CodeHS-Launching@latest/index.html'}
  ]}
];

function init(){
  const grid=document.getElementById('folder-grid');
  let total=0;
  FOLDERS.forEach(f=>{
    total += f.projects.length;
    const card=document.createElement('div');
    card.className='folder-card';
    card.style.borderColor=f.color+'66';
    card.innerHTML=`<div class="card-name" style="color:${f.color}">${f.name}</div><div class="card-desc">${f.projects.length} Projects</div><button class="folder-card-btn" style="background:${f.color}">Open Folder</button>`;
    card.onclick=()=>openFolder(f);
    grid.appendChild(card);
  });
  document.getElementById('footer-count').textContent=FOLDERS.length+' Folders · '+total+' Projects';
}

function openFolder(f){
  document.getElementById('view-home').style.display='none';
  document.getElementById('view-folder').style.display='block';
  document.getElementById('back-btn').className='visible';
  document.getElementById('fv-title').textContent=f.name;
  document.getElementById('fv-title').style.color=f.color;
  const pg=document.getElementById('project-grid');
  pg.innerHTML='';
  f.projects.forEach(p=>{
    const card=document.createElement('div');
    card.className='card';
    card.innerHTML=`<div class="card-name">${p.name}</div><div class="card-desc">${p.desc}</div><button class="card-btn">Launch</button>`;
    card.onclick=()=>openModal(p);
    pg.appendChild(card);
  });
}

function goHome(){
  document.getElementById('view-home').style.display='block';
  document.getElementById('view-folder').style.display='none';
  document.getElementById('back-btn').className='';
}

function openModal(p){
  document.getElementById('modal-name').textContent=p.name;
  document.getElementById('modal-desc').textContent=p.desc;
  document.getElementById('modal-launch').onclick=()=>launch(p.url);
  document.getElementById('overlay').className='open';
}

function closeModal(){document.getElementById('overlay').className=''}

function launch(url){
  const frame=document.getElementById('appframe');
  frame.src=url;
  frame.style.display='block';
  document.getElementById('close-app').style.display='block';
  closeModal();
}

function closeApp(){
  const frame=document.getElementById('appframe');
  frame.src='about:blank';
  frame.style.display='none';
  document.getElementById('close-app').style.display='none';
}

init();
//
